#include <iostream>
#include <vector>
#include <string>
#include <sstream>
#include <stdexcept>
#include <algorithm>
#include <unordered_map>

class Algorithm {
public:
    static std::string solve(const std::string& input) {
        std::istringstream iss(input);
        std::string line;
        std::vector<int> numbers;

        while (std::getline(iss, line)) {
            if (!line.empty()) {
                numbers.push_back(std::stoi(line));
            }
        }

        if (numbers.empty()) {
            return "None";
        }

        std::sort(numbers.begin(), numbers.end());
        std::ostringstream oss;

        for (const auto& num : numbers) {
            oss << num << "\n";
        }

        return oss.str();
    }
};

int main() {
    std::string input = "3\n1\n2\n";
    std::string result = Algorithm::solve(input);
    std::cout << result;

    return 0;
}
